const contentIdeaId = Number($json.body?.contentIdeaId || $json.contentIdeaId || 0);
const topic = String($json.body?.topic || $json.topic || '').trim();
const script = String($json.body?.script || $json.script || '').trim();
const derivedHook = String(script.split(/[.!?\n]/)[0] || topic || '').trim();
const hook = String($json.body?.hook || $json.hook || derivedHook).trim().slice(0, 100);
const caption = String($json.body?.caption || $json.caption || '').trim();
const keyword = String($json.body?.keyword || $json.keyword || topic).trim();
const workflowRunId = Number($json.body?.workflowRunId || $json.workflowRunId || 0);

if (!contentIdeaId || contentIdeaId <= 0) throw new Error('contentIdeaId invalide');
if (!script) throw new Error('script manquant');
if (!hook) throw new Error('hook manquant');
if (!workflowRunId || workflowRunId <= 0) throw new Error('workflowRunId invalide');

if (script.length > 500) throw new Error('script trop long');

return [{ json: { contentIdeaId, topic, script, hook, caption, keyword, workflowRunId } }];

const aesthetic = String($json.choices?.[0]?.message?.content || '').trim().slice(0, 100);
if (!aesthetic) throw new Error('Aesthetic description failed');
return [{ json: { aesthetic } }];

