const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Select Media (Scored)1').item.json.workflowRunId || 0);
const contentIdeaId = $('Select Media (Scored)1').item.json.id;
const shotstackRenderId = $('HTTP: Shotstack Render1').item.json.response?.id || $('HTTP: Shotstack Render1').item.json.id || '';

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing callback config');
}

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Professional render requested from Shotstack.',
  responsePayload: JSON.stringify({
    contentIdeaId,
    shotstackRenderId,
    mediaQuality: $('Select Media (Scored)1').item.json.media_quality,
    mediaScore: $('Select Media (Scored)1').item.json.media_score
  })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

let response = null;
let lastError = null;
for (let attempt = 1; attempt <= 6; attempt += 1) {
  try {
    response = await new Promise((resolve, reject) => {
      const req = client.request({
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          'X-Video-Ops-Callback-Secret': callbackSecret,
          'X-Workflow-Contract-Version': '1',
          'X-Request-Timestamp': Date.now().toString()
        }
      }, (res) => {
        let data = '';
        res.on('data', (chunk) => { data += chunk; });
        res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
      });

      req.on('error', reject);
      req.setTimeout(20000, () => req.destroy(new Error('Callback timeout')));
      req.write(body);
      req.end();
    });

    if (response.statusCode >= 200 && response.statusCode < 300) {
      break;
    }

    lastError = 'Callback failed: ' + response.statusCode;
    if (response.statusCode !== 404 || attempt === 6) {
      throw new Error(lastError);
    }
  } catch (error) {
    lastError = error.message || String(error);
    if (attempt === 6) {
      throw error;
    }
  }

  await sleep(500 * attempt);
}

if (!response || response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error(lastError || 'Callback failed');
}

return [{ json: { ok: true, contentIdeaId, shotstackRenderId, mediaQuality: $('Select Media (Scored)1').item.json.media_quality, callbackStatusCode: response.statusCode } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const contentIdeaId = Number($('Validate Input1').item.json.contentIdeaId || 0);
const workflowRunId = Number($('Validate Input1').item.json.workflowRunId || 0);
const error = $json;

let errorMessage = 'Unknown error';
if (typeof error === 'string') errorMessage = error;
else if (error.message) errorMessage = error.message;
else if (error.error?.message) errorMessage = error.error.message;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { status: 'FAILED', message: 'Missing config' } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Render failed: ' + errorMessage.slice(0, 200),
  responsePayload: JSON.stringify({ contentIdeaId, error: errorMessage.slice(0, 500) })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve) => {
  let attempts = 0;
  const maxAttempts = 2;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
          'X-Workflow-Contract-Version': '1',
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', () => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, 2000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback failed' });
      }
    });

    req.setTimeout(15000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, 2000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback timeout' });
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

return [{ json: { status: 'FAILED', message: 'Error callback sent (best effort)' } }];
